def triples_sum_to_zero(l: list):
    l = list(set(l))
    n = len(l)
    for i in range(n):
        s = set()
        current_sum = -l[i]
        for j in range(i + 1, n):
            if (current_sum - l[j]) in s:
                return True
            s.add(l[j])
    return False
```

